import{c as e,Q as a,j as n,m as r}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Building AI Coding Agents for the Terminal: Scaffolding, Harness, Context Engineering","description":"","frontmatter":{"url":"https://arxiv.org/html/2603.05344v1","title":"Building AI Coding Agents for the Terminal: Scaffolding, Harness, Context Engineering","date":"2026-03-05T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-03-05-opendev-terminal-agents.md","filePath":"research/ai-articles/scored/2026-03-05-opendev-terminal-agents.md","lastUpdated":1779796674000}'),o={name:"research/ai-articles/scored/2026-03-05-opendev-terminal-agents.md"};function s(d,t,i,l,c,h){return a(),n("div",null,[...t[0]||(t[0]=[r(`<h1 id="building-ai-coding-agents-for-the-terminal-scaffolding-harness-context-engineering" tabindex="-1">Building AI Coding Agents for the Terminal: Scaffolding, Harness, Context Engineering <a class="header-anchor" href="#building-ai-coding-agents-for-the-terminal-scaffolding-harness-context-engineering" aria-label="Permalink to &quot;Building AI Coding Agents for the Terminal: Scaffolding, Harness, Context Engineering&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://arxiv.org/html/2603.05344v1" target="_blank" rel="noreferrer">https://arxiv.org/html/2603.05344v1</a><br><strong>作者</strong>：Nghi D. Q. Bui（OpenDev）<br><strong>發表日期</strong>：2026-03-05<br><strong>評分日期</strong>：2026-05-05</p><hr><h2 id="繁體中文全文摘要" tabindex="-1">繁體中文全文摘要 <a class="header-anchor" href="#繁體中文全文摘要" aria-label="Permalink to &quot;繁體中文全文摘要&quot;">​</a></h2><h3 id="研究背景" tabindex="-1">研究背景 <a class="header-anchor" href="#研究背景" aria-label="Permalink to &quot;研究背景&quot;">​</a></h3><p>OpenDev 是一個開源命令列 Agent，專為自主軟體工程任務設計。論文系統性地解決三大終端 Agent 挑戰：有限的 context window、防止破壞性操作、在不耗盡 prompt budget 的情況下擴充能力。</p><h3 id="四層架構" tabindex="-1">四層架構 <a class="header-anchor" href="#四層架構" aria-label="Permalink to &quot;四層架構&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────┐</span></span>
<span class="line"><span>│   Entry &amp; UI Layer（CLI / TUI / Web） │</span></span>
<span class="line"><span>├─────────────────────────────────────┤</span></span>
<span class="line"><span>│   Agent Core Layer（推理與協調）       │</span></span>
<span class="line"><span>├─────────────────────────────────────┤</span></span>
<span class="line"><span>│   Tool &amp; Context Layers（執行與 CM） │</span></span>
<span class="line"><span>├─────────────────────────────────────┤</span></span>
<span class="line"><span>│   Persistence Layer（Session / Logs） │</span></span>
<span class="line"><span>└─────────────────────────────────────┘</span></span></code></pre></div><p>Agent Core 包含：Planner（戰略規劃）、Executor（戰術執行）、Critic（自我評估）、Orchestrator（路由與 context 管理）。</p><h3 id="五層安全架構-defense-in-depth" tabindex="-1">五層安全架構（Defense in Depth） <a class="header-anchor" href="#五層安全架構-defense-in-depth" aria-label="Permalink to &quot;五層安全架構（Defense in Depth）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>層次</th><th>機制</th><th>範例</th></tr></thead><tbody><tr><td><strong>L1 Prompt</strong></td><td>系統提示中明確禁止破壞性操作</td><td>「未經確認不得刪除文件」</td></tr><tr><td><strong>L2 Schema</strong></td><td>工具 schema 包含安全約束</td><td><code>rm</code> 只有 <code>--confirm</code> 版本可用</td></tr><tr><td><strong>L3 Runtime</strong></td><td>破壞性操作需明確核准</td><td>互動式 <code>[y/n]</code> 確認</td></tr><tr><td><strong>L4 Tool</strong></td><td>工具調用前驗證，結果後驗證</td><td>路徑驗證防目錄穿越攻擊</td></tr><tr><td><strong>L5 Hooks</strong></td><td>使用者定義的生命週期鉤子</td><td>自訂鉤子對照 protected-files 清單</td></tr></tbody></table><p><strong>核心原則</strong>：任何單一層次的失效都不能危害安全，必須繞過多個獨立層次才能觸發有害操作。</p><h3 id="context-工程-核心設計" tabindex="-1">Context 工程（核心設計） <a class="header-anchor" href="#context-工程-核心設計" aria-label="Permalink to &quot;Context 工程（核心設計）&quot;">​</a></h3><h4 id="動態系統提示" tabindex="-1">動態系統提示 <a class="header-anchor" href="#動態系統提示" aria-label="Permalink to &quot;動態系統提示&quot;">​</a></h4><p>取代靜態提示，根據當前狀態動態組裝：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>當前任務：修復 auth 模組的記憶體洩漏</span></span>
<span class="line"><span>進度：8 個子任務中的第 3 個</span></span>
<span class="line"><span>可用工具：[shell, file_read, grep, valgrind]</span></span>
<span class="line"><span>Context Budget：60% 剩餘（60K / 100K tokens）</span></span></code></pre></div><h4 id="工具結果最佳化" tabindex="-1">工具結果最佳化 <a class="header-anchor" href="#工具結果最佳化" aria-label="Permalink to &quot;工具結果最佳化&quot;">​</a></h4><p>終端輸出通常冗長且重複，OpenDev 智慧壓縮：</p><ul><li><strong>截斷 + 保留結構</strong>：保留前 10 行（目錄結構）+ 後 10 行（摘要）</li><li><strong>移除 ANSI color codes</strong>：token 數減少 10-20%</li><li><strong>錯誤摘要化</strong>：2000 行編譯輸出 → 5 個錯誤類型 + 首個錯誤詳情</li><li><strong>去重</strong>：緩存結果，只提供 delta</li></ul><h4 id="雙記憶架構" tabindex="-1">雙記憶架構 <a class="header-anchor" href="#雙記憶架構" aria-label="Permalink to &quot;雙記憶架構&quot;">​</a></h4><table tabindex="0"><thead><tr><th>記憶類型</th><th>位置</th><th>大小</th><th>壽命</th></tr></thead><tbody><tr><td><strong>Working Memory</strong></td><td>in-prompt</td><td>10-20K tokens</td><td>當前 session</td></tr><tr><td><strong>Episodic Memory</strong></td><td>持久儲存</td><td>持續增長</td><td>專案壽命</td></tr></tbody></table><h4 id="自適應-compaction-80-閾值" tabindex="-1">自適應 Compaction（80% 閾值） <a class="header-anchor" href="#自適應-compaction-80-閾值" aria-label="Permalink to &quot;自適應 Compaction（80% 閾值）&quot;">​</a></h4><p>達到 context 閾值時：</p><ol><li>辨識關鍵資訊（目標、最近 10 步、當前狀態）</li><li>壓縮歷史（早期行動摘要化，同類操作合併）</li><li>保持因果連續性</li><li>典型壓縮率：40-60%</li></ol><h4 id="context-aware-提醒" tabindex="-1">Context-Aware 提醒 <a class="header-anchor" href="#context-aware-提醒" aria-label="Permalink to &quot;Context-Aware 提醒&quot;">​</a></h4><p>對抗指令降解（instruction degradation）：</p><ul><li>安全提醒：觸發於危險操作之前</li><li>目標提醒：觸發於偏離目標行為</li><li>資源提醒：context 接近上限時</li><li>進度提醒：固定間隔</li></ul><h3 id="多模型架構" tabindex="-1">多模型架構 <a class="header-anchor" href="#多模型架構" aria-label="Permalink to &quot;多模型架構&quot;">​</a></h3><table tabindex="0"><thead><tr><th>角色</th><th>典型模型</th><th>Token Budget</th></tr></thead><tbody><tr><td>正常執行</td><td>Claude 3.5 Sonnet</td><td>2000</td></tr><tr><td>深度思考</td><td>Claude 3.5 Opus</td><td>5000</td></tr><tr><td>自我批判</td><td>Claude 3.5 Sonnet</td><td>1000</td></tr><tr><td>視覺分析</td><td>Claude 3.5 Sonnet</td><td>3000</td></tr><tr><td>領域專家</td><td>Claude 3.5 Opus</td><td>5000</td></tr></tbody></table><h3 id="雙代理分離-planner-vs-executor" tabindex="-1">雙代理分離：Planner vs. Executor <a class="header-anchor" href="#雙代理分離-planner-vs-executor" aria-label="Permalink to &quot;雙代理分離：Planner vs. Executor&quot;">​</a></h3><p><strong>Planner</strong>：戰略任務分解，每個主要任務階段執行一次，Token 2000-3000 <strong>Executor</strong>：戰術具體行動，每分鐘多次，Token 1500-2500</p><h3 id="懶加載工具發現-lazy-tool-discovery-via-mcp" tabindex="-1">懶加載工具發現（Lazy Tool Discovery via MCP） <a class="header-anchor" href="#懶加載工具發現-lazy-tool-discovery-via-mcp" aria-label="Permalink to &quot;懶加載工具發現（Lazy Tool Discovery via MCP）&quot;">​</a></h3><p><strong>問題</strong>：列出所有工具 = 5000+ tokens（docker、k8s、terraform、ansible...） <strong>解決方案</strong>：</p><ul><li>基礎工具：[shell, file_read, file_write]（永遠可用）</li><li>按需加載：當 Agent 需要編譯 C++ 時，動態加載 [gcc, clang, make, cmake]</li><li>成本：約 500 tokens，只在需要時才載入</li></ul><h3 id="效能結果" tabindex="-1">效能結果 <a class="header-anchor" href="#效能結果" aria-label="Permalink to &quot;效能結果&quot;">​</a></h3><ul><li>SWE-agent（基準）：41% on SWE-bench Verified</li><li>OpenDev（本論文）：<strong>48% on SWE-bench Verified</strong></li></ul><h3 id="對-workspace-的啟示" tabindex="-1">對 Workspace 的啟示 <a class="header-anchor" href="#對-workspace-的啟示" aria-label="Permalink to &quot;對 Workspace 的啟示&quot;">​</a></h3><ol><li><strong>五層安全架構</strong>：cc-workspace 的 pre-commit hook + production 二次確認機制對應 L1/L3，可進一步加入 schema-level 的工具限制</li><li><strong>動態系統提示</strong>：context-monitor-table.md 的觸發機制與此一致，可借鑒「context budget reminder」納入提示詞</li><li><strong>Lazy Tool Loading</strong>：MCP server 按需啟用的策略與 Skill 按需載入一致，減少 context 污染</li><li><strong>Planner/Executor 分離</strong>：cc-workspace 的 parent Agent（規劃）+ sub-agent（執行）架構的理論驗證</li></ol><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>8/10</td><td>五層安全、動態提示、lazy tool loading 均可直接對照 cc-workspace 機制</td></tr><tr><td>B. 創新性</td><td>7/10</td><td>Lazy MCP tool discovery 和 context-aware reminders 是新穎的系統設計</td></tr><tr><td>C. 證據品質</td><td>7/10</td><td>SWE-bench 量化結果（48% vs 41%），但論文本身描述性偏多，ablation 不足</td></tr><tr><td>D. 技術深度</td><td>9/10</td><td>全面的架構文件：四層架構、五層安全、六階段 ReAct、雙記憶架構，均有詳細說明</td></tr><tr><td>E. 泛化性</td><td>8/10</td><td>通用終端 Agent 設計模式，不限特定代碼庫或語言</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.75/10</strong></td><td>8×0.3 + 7×0.2 + 7×0.2 + 9×0.15 + 8×0.15 = 2.4+1.4+1.4+1.35+1.2</td></tr></tbody></table><p><strong>整合決策</strong>：Rule<br><strong>整合位置</strong>：<code>.claude/refs/harness-design.md</code>（五層安全、雙代理模式）<br><strong>整合狀態</strong>：待實作</p><p><strong>TODO</strong>：</p><ul><li>將五層安全架構概念加入 harness-design.md 的「安全層」段落</li><li>在 context-monitor-table.md 中加入 context budget reminder 機制（80% 觸發）</li><li>評估是否採用 Planner/Executor 明確分離的 sub-agent 結構替代當前 parent + sub 模式</li></ul>`,44)])])}const u=e(o,[["render",s]]);export{g as __pageData,u as default};
